-- Add a reusable 200-word food and restaurant deck with pre-generated audio.
insert into public.template_decks (slug, name, description, level)
values (
  'am-thuc-goi-mon-200',
  'Ẩm thực và gọi món - 200 từ',
  '200 từ vựng tiếng Trung thực tế về nguyên liệu, món ăn, khẩu vị, gia vị, cách chế biến, dị ứng thực phẩm và giao tiếp nhà hàng. Mỗi từ có pinyin, nghĩa tiếng Việt, câu ví dụ theo ngữ cảnh và hai audio tạo sẵn.',
  'Ẩm thực'
)
on conflict (slug) do update
set name = excluded.name, description = excluded.description, level = excluded.level;

with target_deck as (
  select id from public.template_decks where slug = 'am-thuc-goi-mon-200'
)
insert into public.template_cards (
  template_deck_id, chinese, pinyin, meaning_vi, example_cn,
  example_pinyin, example_vi, word_audio_url, sentence_audio_url, position
)
select
  target_deck.id, card.chinese, card.pinyin, card.meaning_vi,
  card.example_cn, card.example_pinyin, card.example_vi,
  card.word_audio_url, card.sentence_audio_url, card.position
from target_deck
cross join (
  values
    ('订位', 'dìng wèi', 'đặt bàn', '您好，我想订位晚上七点，有四个人。', 'Nín hǎo, wǒ xiǎng dìng wèi wǎn shàng qī diǎn, yǒu sì gè rén.', 'Xin chào, tôi muốn đặt bàn lúc 7 giờ tối, có 4 người.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-4c339c062609bc5724a9d1f0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-a47baed13fd0385d96b8d472.mp3', 1),
    ('空桌', 'kòng zhuō', 'bàn trống', '请问这儿还有空桌子可以坐吗？', 'Qǐng wèn zhè ér hái yǒu kòng zhuō zi kě yǐ zuò ma?', 'Xin hỏi ở đây còn bàn trống để ngồi không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-a2236c8c09d2890ca097fecd.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-c35efc5502b5c059f89d2dfd.mp3', 2),
    ('菜单', 'cài dān', 'thực đơn', '请给我菜单，我想看看有哪些菜品。', 'Qǐng gěi wǒ cài dān, wǒ xiǎng kàn kàn yǒu nǎ xiē cài pǐn.', 'Làm ơn đưa tôi thực đơn, tôi muốn xem có những món ăn nào.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-4ce4cafdd0561280fd6d83b0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-3c11d2b622d78ce4742e70ec.mp3', 3),
    ('点菜', 'diǎn cài', 'gọi món', '我们准备好了，可以开始点菜了吗？', 'Wǒ men zhǔn bèi hǎo le, kě yǐ kāi shǐ diǎn cài le ma?', 'Chúng tôi đã chuẩn bị xong, có thể bắt đầu gọi món không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-111bb0cd52189d59d24ffa1d.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-fc922c82b6d868b82e606202.mp3', 4),
    ('特色菜', 'tè sè cài', 'món đặc biệt', '这家餐厅的特色菜是麻辣火锅，非常有名。', 'Zhè jiā cān tīng de tè sè cài shì má là huǒ guō, fēi cháng yǒu míng.', 'Món đặc biệt của nhà hàng này là lẩu cay, rất nổi tiếng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-f8cc9236153c260d02cc5533.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-2e88c80626e3ae278b7ae403.mp3', 5),
    ('主菜', 'zhǔcài', 'món chính', '请问今天有什么主菜推荐？', 'Qǐngwèn jīntiān yǒu shénme zhǔcài tuījiàn?', 'Xin hỏi hôm nay có món chính nào được đề xuất?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-f572a04106d0f628ca973565.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-b660b683d89c39c7b9a51db9.mp3', 6),
    ('配菜', 'pèi cài', 'món phụ', '这道主菜配菜包括炒青菜和米饭。', 'Zhè dào zhǔ cài pèi cài bāo kuò chǎo qīng cài hé mǐ fàn.', 'Món chính này có món phụ bao gồm rau xào và cơm.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-065e034d649307249a1b69ca.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-60680d38b6bfd97633fcea05.mp3', 7),
    ('份', 'fèn', 'khẩu phần', '请给我两份宫保鸡丁，谢谢。', 'Qǐng gěi wǒ liǎng fèn gōng bǎo jī dīng, xiè xiè.', 'Làm ơn cho tôi hai khẩu phần gà xào cay.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-0066134b36c48ded7095bf1f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-5d0f2f9fc7bf0f7d6f72fa86.mp3', 8),
    ('加菜', 'jiā cài', 'thêm món', '我们还要加菜，可以帮忙点几个小吃吗？', 'Wǒ men hái yào jiā cài, kě yǐ bāng máng diǎn jǐ gè xiǎo chī ma?', 'Chúng tôi muốn thêm món, có thể giúp đặt một vài món ăn nhẹ không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-d2da5cc45989967e81d3419d.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-adead8f844f84097b7116a1c.mp3', 9),
    ('服务员', 'fú wù yuán', 'nhân viên phục vụ', '服务员，请问这道菜有没有过敏原？', 'Fú wù yuán, qǐng wèn zhè dào cài yǒu méi yǒu guò mǐn yuán?', 'Nhân viên phục vụ, xin hỏi món này có chất gây dị ứng không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-cf80aba698b91219da545906.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-5390a67f92a173f2a9e28526.mp3', 10),
    ('订座确认', 'dìng zuò què rèn', 'xác nhận đặt bàn', '请问您能帮我订座确认今晚的预约吗？', 'Qǐng wèn nín néng bāng wǒ dìng zuò què rèn jīn wǎn de yù yuē ma?', 'Bạn có thể giúp tôi xác nhận đặt bàn cho tối nay không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-604b4d14f06dc47fcc0e0ae1.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-9ea5bb0203152a427265af86.mp3', 11),
    ('叫号取餐', 'jiào hào qǔ cān', 'gọi số lấy món', '您的餐点好了，可以根据叫号取餐。', 'Nín de cān diǎn hǎo le, kě yǐ gēn jù jiào hào qǔ cān.', 'Món ăn của bạn đã sẵn sàng, có thể lấy theo số gọi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-45aebda81ca35d32d39241c4.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-f5167ca50a57afb026572e12.mp3', 12),
    ('推荐菜', 'tuī jiàn cài', 'món được khuyên dùng', '请问服务员，有没有推荐菜适合小孩？', 'Qǐng wèn fú wù yuán, yǒu méi yǒu tuī jiàn cài shì hé xiǎo hái?', 'Xin hỏi nhân viên phục vụ có món nào được khuyên dùng cho trẻ em không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-a2b1822f6c1941fff3dbc384.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-26c1a579a66feeb515229919.mp3', 13),
    ('套餐', 'tào cān', 'set ăn', '请问有几个套餐供我们选择？', 'Qǐng wèn yǒu jǐ gè tào cān gōng wǒ men xuǎn zé?', 'Xin hỏi có mấy set ăn để chúng tôi lựa chọn?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-c1cfa1340c62d3da906375d0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-dddc27abb87d10e1b3690dcc.mp3', 14),
    ('等位', 'děngwèi', 'chờ bàn', '周末来这家餐厅通常需要等位。', 'Zhōumò lái zhè jiā cāntīng tōngcháng xūyào děngwèi.', 'Cuối tuần đến nhà hàng này thường phải chờ bàn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-c9c73ec6916980940a3126d1.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-a37be26ead35291b890facf4.mp3', 15),
    ('用餐人数', 'yòngcān rénshù', 'số người dùng bữa', '请告诉我用餐人数，我来安排座位。', 'Qǐng gàosu wǒ yòngcān rénshù, wǒ lái ānpái zuòwèi.', 'Vui lòng cho tôi biết số người dùng bữa để tôi xếp chỗ.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-95103b136e4528ea62d0ea82.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-dc000103646c5a48062e3398.mp3', 16),
    ('无过敏原', 'wú guò mǐn yuán', 'không có chất gây dị ứng', '这份沙拉是无过敏原，适合所有人食用。', 'Zhè fèn shā lā shì wú guò mǐn yuán, shì hé suǒ yǒu rén shí yòng.', 'Phần salad này không có chất gây dị ứng, phù hợp mọi người dùng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-8ba8dfd5d5a56f1c9239c0f1.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-6d910f671c3bd842468d6c20.mp3', 17),
    ('服务费', 'fú wù fèi', 'phí phục vụ', '请问账单里有包含服务费吗？', 'Qǐng wèn zhàng dān lǐ yǒu bāo hán fú wù fèi ma?', 'Xin hỏi trong hóa đơn có bao gồm phí phục vụ không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-f8b8b0ce565c90db256acae6.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-7e21b98579140485df9bad8b.mp3', 18),
    ('卫生间', 'wèi shēng jiān', 'nhà vệ sinh', '请问卫生间在哪里？我想去洗手。', 'Qǐng wèn wèi shēng jiān zài nǎ lǐ? Wǒ xiǎng qù xǐ shǒu.', 'Xin hỏi nhà vệ sinh ở đâu? Tôi muốn rửa tay.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-091ef162c8ed3e4ac8139d82.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-07b47c428f0ed76477a6b568.mp3', 19),
    ('结账', 'jié zhàng', 'tính tiền', '我们吃完了，可以结账了吗？', 'Wǒ men chī wán le, kě yǐ jié zhàng le ma?', 'Chúng tôi ăn xong rồi, có thể tính tiền được chưa?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-374775c3c812f4064cc16ca7.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-d72c0f296e15417c9008e89d.mp3', 20),
    ('饮料单', 'yǐn liào dān', 'menu đồ uống', '请给我饮料单，我想点杯果汁。', 'Qǐng gěi wǒ yǐn liào dān, wǒ xiǎng diǎn bēi guǒ zhī.', 'Làm ơn đưa tôi menu đồ uống, tôi muốn gọi một cốc nước trái cây.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-e101d9f70bd8bea71a05be86.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-30b14636d96ea220df15ad42.mp3', 21),
    ('含麸质', 'hán fū zhì', 'có chứa gluten', '这道菜含麸质，对敏感者不适合。', 'Zhè dào cài hán fū zhì, duì mǐn gǎn zhě bù shì hé.', 'Món này có chứa gluten, không phù hợp cho người nhạy cảm.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-13f320020325a057c7d419d7.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-03f894aab95bc1192992155a.mp3', 22),
    ('素食', 'sù shí', 'món chay', '请问有素食菜单吗？我吃素。', 'Qǐng wèn yǒu sù shí cài dān ma? Wǒ chī sù.', 'Xin hỏi có thực đơn món chay không? Tôi ăn chay.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-1f88337baf2604f164da9a5c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-6ced6a0e5c135d1e6c7ebd36.mp3', 23),
    ('加水', 'jiā shuǐ', 'thêm nước', '麻烦给我们加水，谢谢服务员。', 'Má fan gěi wǒ men jiā shuǐ, xiè xiè fú wù yuán.', 'Làm ơn cho chúng tôi thêm nước, cảm ơn nhân viên phục vụ.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-9b6879dad9940ca987375fad.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-8551ea4afcd215cd9ab19e56.mp3', 24),
    ('辣椒过敏', 'là jiāo guò mǐn', 'dị ứng với ớt', '我有辣椒过敏，点菜时请注意安全。', 'Wǒ yǒu là jiāo guò mǐn, diǎn cài shí qǐng zhù yì ān quán.', 'Tôi bị dị ứng với ớt, khi gọi món xin hãy chú ý an toàn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-23f362bc2812c47f55a6c100.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-20df2df86f6baf1832720422.mp3', 25),
    ('大米', 'dà mǐ', 'gạo', '这道菜主要用大米做成，口感非常香糯。', 'Zhè dào cài zhǔyào yòng dà mǐ zuò chéng, kǒu gǎn fēicháng xiāng nuò.', 'Món này chủ yếu làm từ gạo, hương vị rất thơm và dẻo.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-9c4b23d6a0b97bfce516f381.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-61533754114b59191cbc70e0.mp3', 26),
    ('面条', 'miàn tiáo', 'mì', '请问你们的招牌面条是否含有鸡蛋？', 'Qǐng wèn nǐmen de zhāopái miàn tiáo shìfǒu hányǒu jīdàn?', 'Cho tôi hỏi mì đặc trưng của quán có chứa trứng không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-0b5480e007c777a726006bab.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-721bd1d5a049e70b5e1a6412.mp3', 27),
    ('面粉', 'miàn fěn', 'bột mì', '用面粉做的馒头软而有弹性，非常受欢迎。', 'Yòng miàn fěn zuò de mán tou ruǎn ér yǒu tán xìng, fēicháng shòu huānyíng.', 'Bánh bao làm từ bột mì mềm và dai, rất được yêu thích.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-21eaff4331362c332388f9e4.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-1fc7e33868f943d021e38a56.mp3', 28),
    ('鸡蛋', 'jī dàn', 'trứng', '这道菜含鸡蛋，如果您过敏请告诉我们。', 'Zhè dào cài hán jī dàn, rúguǒ nín guòmǐn qǐng gàosù wǒmen.', 'Món này có chứa trứng, nếu anh/chị bị dị ứng hãy báo cho chúng tôi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-e9f5b71a472d27bbaf9686b9.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-7a90897ff96b10953b050d9a.mp3', 29),
    ('牛奶', 'niú nǎi', 'sữa bò', '甜点里含有牛奶，乳糖不耐请慎重点。', 'Tián diǎn lǐ hányǒu niú nǎi, rǔtáng bù nài qǐng shènzhòng diǎn.', 'Tráng miệng có sữa bò, người không dung nạp lactose hãy cân nhắc.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-b892a42b9695881d77512e97.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-707765f28281bbfb81892c2c.mp3', 30),
    ('豆腐', 'dòu fu', 'đậu phụ', '这盘豆腐新鲜制作，口感滑嫩。', 'Zhè pán dòu fu xīnxiān zhìzuò, kǒu gǎn huá nèn.', 'Đĩa đậu phụ này được làm tươi, vị mềm mượt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-4fc10d8f397780f3b9935b16.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-99939185301eae04ad9143cd.mp3', 31),
    ('食用油', 'shí yòng yóu', 'dầu ăn', '请问食用油是花生油还是菜籽油？', 'Qǐng wèn shí yòng yóu shì huā shēng yóu háishi cài zǐ yóu?', 'Xin hỏi dầu ăn là dầu đậu phộng hay dầu cải?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-c8ba8b9b5cc450565dd6c65f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-5eaae06ed5612d23b96e5caa.mp3', 32),
    ('黄油', 'huáng yóu', 'bơ', '这款面包含黄油，乳制品过敏者请特别注意。', 'Zhè kuǎn miànbāo hán huáng yóu, rǔ zhìpǐn guòmǐn zhě qǐng tèbié zhùyì.', 'Bánh mì này có bơ, người dị ứng sản phẩm từ sữa xin chú ý.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-2aef3d11527dea4681213d17.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-1184cbb2ff995862dc2d7055.mp3', 33),
    ('糖', 'táng', 'đường', '这道甜品用的白糖量不多，口感适中且不过甜。', 'Zhè dào tián pǐn yòng de bái táng liàng bù duō, kǒu gǎn shì zhōng qiě bù guò tián.', 'Món tráng miệng này dùng đường trắng lượng ít, vị vừa phải không ngọt quá.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-c86bc88f26043273549fe166.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-a61d48d824020c9810a4285e.mp3', 34),
    ('盐', 'yán', 'muối', '请问这道菜的盐放多了吗？我喜欢口味清淡。', 'Qǐng wèn zhè dào cài de yán fàng duō le ma? Wǒ xǐhuān kǒu wèi qīng dàn.', 'Xin hỏi món này muối cho nhiều không? Tôi thích vị nhạt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-9e3e97236c4ecaf22657d827.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-b208cb9645dc46efff4e3a6f.mp3', 35),
    ('大蒜', 'dà suàn', 'tỏi', '这道菜含有大蒜，吃完可能口气会有些异味。', 'Zhè dào cài hán yǒu dà suàn, chī wán kě néng kǒu qì huì yǒu xiē yì wèi.', 'Món này có tỏi, ăn xong có thể hơi hôi miệng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-2053d8521c937de25ee497e7.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-3ac917ebb749df0f7f1f0ddb.mp3', 36),
    ('生姜', 'shēng jiāng', 'gừng', '请告诉我这汤里是否放了生姜？我对它不过敏。', 'Qǐng gàosù wǒ zhè tāng lǐ shì fǒu fàng le shēng jiāng? Wǒ duì tā bù guòmǐn.', 'Xin cho biết trong canh có cho gừng không? Tôi không bị dị ứng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-4685ff1a62239a621fbd4527.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-18fac1ccecc980d91bdf5050.mp3', 37),
    ('洋葱', 'yángcōng', 'hành tây', '这道菜有洋葱，食用后可能会有辛辣口感。', 'Zhè dào cài yǒu yáng cōng, shí yòng hòu kě néng huì yǒu xīn là kǒu gǎn.', 'Món này có hành tây nên khi ăn có thể cảm nhận vị cay nhẹ.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-edc855182ce2f997bfc2c14a.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-8e69e9ac96343cf03411c80a.mp3', 38),
    ('糯米', 'nuò mǐ', 'gạo nếp', '这款甜点是用糯米制作，口感软糯香甜。', 'Zhè kuǎn tián diǎn shì yòng nuò mǐ zhì zuò, kǒu gǎn ruǎn nuò xiāng tián.', 'Món tráng miệng này làm từ gạo nếp, vị mềm dẻo và ngọt thơm.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-be5e4cd867092013fc1104f4.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-6e7c6853398df8c614e1857d.mp3', 39),
    ('手擀面', 'shǒu gǎn miàn', 'mì sợi tự làm', '这碗手擀面用新鲜面粉制作，非常筋道。', 'Zhè wǎn shǒu gǎn miàn yòng xīn xiān miàn fěn zhì zuò, fēi cháng jīn dào.', 'Bát mì sợi tự làm này dùng bột mì mới, rất dai ngon.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-c46966d39b5939584690f8f6.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-4f98bf9e579b671b6e841dee.mp3', 40),
    ('豆浆', 'dòu jiāng', 'sữa đậu nành', '豆浆是本店早餐的传统饮品，不含乳制品。', 'Dòu jiāng shì běn diàn zǎo cān de chuán tǒng yǐn pǐn, bù hán rǔ zhìpǐn.', 'Sữa đậu nành là đồ uống truyền thống cho bữa sáng của quán, không chứa sữa bò.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-9c61c36d4df7f90962024b25.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-7a97d29ea04ea6953f9f307c.mp3', 41),
    ('植物油', 'zhí wù yóu', 'dầu thực vật', '厨房里使用的植物油不含过敏成分，安全健康。', 'Chú fáng lǐ shǐ yòng de zhí wù yóu bù hán guò mǐn chéng fèn, ān quán jiàn kāng.', 'Dầu thực vật dùng trong bếp không có thành phần gây dị ứng, an toàn và lành mạnh.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-82da696404dbf3105c31aa15.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-605e705ef620c51e06cf3c9c.mp3', 42),
    ('奶油', 'nǎiyóu', 'kem sữa', '这款甜点含奶油成分，乳制品过敏者慎用。', 'Zhè kuǎn tián diǎn hán nǎi yóu chéng fèn, rǔ zhì pǐn guò mǐn zhě shèn yòng.', 'Món tráng miệng này có kem sữa, người dị ứng sản phẩm từ sữa cần thận trọng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-ed3cdb192a56efc6ff0b060f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-98946f869ef5711a71764d41.mp3', 43),
    ('冰糖', 'bīng táng', 'đường phèn', '汤里加了冰糖，口味甜而不腻，非常适合冬季饮用。', 'Tāng lǐ jiā le bīng táng, kǒu wèi tián ér bù nì, fēi cháng shì hé dōng jì yǐn yòng.', 'Canh có cho đường phèn, vị ngọt mà không gắt, rất thích hợp uống mùa đông.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-80445df157f1e9be42d019a2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-912bdc5fbc5b50be9132f909.mp3', 44),
    ('海盐', 'hǎi yán', 'muối biển', '这道菜使用了海盐，带有独特的咸鲜味道。', 'Zhè dào cài shǐ yòng le hǎi yán, dài yǒu dú tè de xián xiān wèi dào.', 'Món này sử dụng muối biển, có vị mặn đậm đà đặc trưng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-e901ac0968c5a34fa8fb0b7f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-32651d676900b25170e01aae.mp3', 45),
    ('蒜末', 'suàn mò', 'tỏi băm', '请少放蒜末，我对大蒜过敏。', 'Qǐng shǎo fàng suàn mò, wǒ duì dà suàn guò mǐn.', 'Xin cho ít tỏi băm, tôi bị dị ứng tỏi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-8d102ab1ce990ebeb62e6f8a.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-22536058a7cf0ea6e8cca88d.mp3', 46),
    ('姜片', 'jiāng piàn', 'gừng thái lát', '这道汤里加了姜片，味道鲜美且暖胃。', 'Zhè dào tāng lǐ jiā le jiāng piàn, wèi dào xiān měi qiě nuǎn wèi.', 'Canh này có gừng thái lát, vị ngon và ấm bụng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-c02c03a3b70881e5ce18e437.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-71e8e0d88f5daeefab5b7107.mp3', 47),
    ('青葱', 'qīng cōng', 'hành lá', '炒菜时加入新鲜的青葱，使味道更浓郁。', 'Chǎo cài shí jiā rù xīn xiān de qīng cōng, shǐ wèi dào gèng nóng yù.', 'Khi xào cho hành lá tươi để món ăn thơm hơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-7fab6f1b4650921cf0240413.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-e5f74e31f68115cafadf820b.mp3', 48),
    ('糙米', 'cāo mǐ', 'gạo lứt', '餐厅提供健康的糙米饭，适合注重营养的人。', 'Cān tīng tí gōng jiàn kāng de cāo mǐ fàn, shì hé zhù zhòng yíng yǎng de rén.', 'Nhà hàng có phục vụ cơm gạo lứt healthy, thích hợp người chú trọng dinh dưỡng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-5e272ed2d64999372294d2fc.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-9bed02587ce75dd0073283b3.mp3', 49),
    ('拉面', 'lā miàn', 'mì kéo sợi', '拉面用传统手工方法制成，口感劲道。', 'Lā miàn yòng chuán tǒng shǒu gōng fāng fǎ zhì chéng, kǒu gǎn jìn dào.', 'Mì kéo sợi làm theo phương pháp thủ công truyền thống, vị dai chắc.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-c4647dac196c870e25aa0662.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-770c7d20c113786f0b4af5a2.mp3', 50),
    ('牛肉', 'niú ròu', 'thịt bò', '我想点一份牛肉，请问这道菜辣不辣？', 'Wǒ xiǎng diǎn yí fèn niú ròu, qǐngwèn zhè dào cài là bù là?', 'Tôi muốn gọi một phần thịt bò, cho hỏi món này có cay không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-70099ea01925d3dad8b6cec7.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-a26fa89caf3b52dbbd834aef.mp3', 51),
    ('猪肉', 'zhū ròu', 'thịt heo', '这家店的猪肉炒得很嫩，我过去常来吃。', 'Zhè jiā diàn de zhū ròu chǎo dé hěn nèn, wǒ guòqù cháng lái chī.', 'Thịt heo xào ở quán này rất mềm, trước tôi thường đến đây ăn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-98fe6354d015ccb6ace99f8e.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-4e2b510487758574fa747d89.mp3', 52),
    ('鸡肉', 'jī ròu', 'thịt gà', '服务员，请给我推荐一款鸡肉菜，谢谢。', 'Fúwùyuán, qǐng gěi wǒ tuījiàn yī kuǎn jī ròu cài, xièxiè.', 'Phục vụ ơi, làm ơn giới thiệu cho tôi một món thịt gà, cảm ơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-d564e7d1c8e63e77592badcc.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-b8299c72a3f999e3d1816a54.mp3', 53),
    ('鸭肉', 'yā ròu', 'thịt vịt', '北京烤鸭是有名的鸭肉美食，你尝过吗？', 'Běijīng kǎo yā shì yǒumíng de yā ròu měishí, nǐ cháng guò ma?', 'Vịt quay Bắc Kinh là món vịt nổi tiếng, bạn đã thử chưa?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-5dd8f72742349ce7f19d6a02.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-f01fa12899ee51f7eb4e8a3e.mp3', 54),
    ('鱼', 'yú', 'cá', '请问鱼是当天现杀的吗？我对海鲜过敏。', 'Qǐngwèn yú shì dāngtiān xiàn shā de ma? Wǒ duì hǎixiān guòmǐn.', 'Cho hỏi cá hôm nay là cá mới bắt không? Tôi bị dị ứng hải sản.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-ac3069de682490aca2ec37da.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-def8de9844ed8392cb39e6ac.mp3', 55),
    ('虾', 'xiā', 'tôm', '因为对虾过敏，我不能点这道虾仁炒饭。', 'Yīnwèi duì xiā guòmǐn, wǒ bùnéng diǎn zhè dào xiā rén chǎofàn.', 'Vì dị ứng tôm, tôi không thể gọi món cơm chiên tôm này.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-86902fa0e945aac81dbc77d6.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-d82aa11b01216b8eb5fd9e7b.mp3', 56),
    ('墨鱼', 'mò yú', 'mực', '我喜欢吃清炒墨鱼，味道很鲜美。', 'Wǒ xǐhuān chī qīng chǎo mò yú, wèidào hěn xiānměi.', 'Tôi thích ăn mực xào đơn giản, vị rất tươi ngon.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-44a65c358a974fff013a8cfb.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-76d7a63f0cdd43019abd7062.mp3', 57),
    ('海鲜', 'hǎixiān', 'hải sản', '这家餐厅的海鲜非常新鲜，请放心食用。', 'Zhè jiā cāntīng de hǎixiān fēicháng xīnxiān, qǐng fàngxīn shíyòng.', 'Hải sản ở nhà hàng này rất tươi, bạn hãy yên tâm ăn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-db596f12194a643a2b4eca5b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-e922b3cd0a46cb8d572e9427.mp3', 58),
    ('菠菜', 'bōcài', 'rau chân vịt (rau cải bó xôi)', '菠菜含有丰富的铁质，适合补血。', 'Bōcài hányǒu fēngfù de tiězhi, shìhé bǔ xuè.', 'Rau chân vịt chứa nhiều sắt, thích hợp để bổ máu.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-2babb323b7140a333c3ea118.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-f8372990e24e7b2cf7e445eb.mp3', 59),
    ('香菇', 'xiānggū', 'nấm hương', '请问这道菜用的是新鲜香菇还是干香菇？', 'Qǐngwèn zhè dào cài yòng de shì xīnxiān xiānggū háishì gān xiānggū?', 'Cho hỏi món này dùng nấm hương tươi hay nấm khô?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-2d7fe74d093b5907ce0af9e6.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-2d6e22a49ef2d2ade3be4615.mp3', 60),
    ('土豆', 'tǔdòu', 'khoai tây', '土豆可以炸着吃，也可以煮着吃，很百搭。', 'Tǔdòu kěyǐ zhá zhe chī, yě kěyǐ zhǔ zhe chī, hěn bǎidā.', 'Khoai tây có thể chiên hay luộc đều ngon, rất dễ phối.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-a64a92c8653029063a71c374.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-e825737596a22e8cb09bfdaf.mp3', 61),
    ('苹果', 'píngguǒ', 'táo', '饭后来一个苹果，有助消化也健康。', 'Fàn hòu lái yí gè píngguǒ, yǒuzhù xiāohuà yě jiànkāng.', 'Ăn một quả táo sau bữa ăn giúp tiêu hóa và tốt cho sức khỏe.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-50537dab76505dfc66dc7841.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-fbd8b72d2b79a07f413996ba.mp3', 62),
    ('牛排', 'niú pái', 'bò bít tết', '这道牛排是用新鲜牛肉现做的，推荐试试。', 'Zhè dào niú pái shì yòng xīnxiān niúròu xiàn zuò de, tuījiàn shì shì.', 'Bò bít tết này làm từ thịt bò tươi, tôi khuyên bạn thử.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-dfe5cc3df3047299552ea4f3.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-b7249ee8bc5f93da30d0898f.mp3', 63),
    ('火锅', 'huǒguō', 'lẩu', '冬天吃火锅最暖和，也适合朋友聚会。', 'Dōngtiān chī huǒguō zuì nuǎnhuo, yě shìhé péngyǒu jùhuì.', 'Ăn lẩu vào mùa đông rất ấm áp, cũng phù hợp tụ họp bạn bè.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-8d56ca5e36ec8d4f732c48dc.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-7e31b808e2d5cd739366ba53.mp3', 64),
    ('龙虾', 'lóngxiā', 'tôm hùm', '我对海鲜不过敏，但龙虾会让我过敏。', 'Wǒ duì hǎixiān bù guòmǐn, dàn lóngxiā huì ràng wǒ guòmǐn.', 'Tôi không dị ứng hải sản, nhưng tôm hùm thì dị ứng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-1102ded688a594d51dfced91.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-7b99f1b17ecc003a7e2fe57b.mp3', 65),
    ('生蚝', 'shēngháo', 'hàu', '生蚝必须新鲜，否则容易引起食物中毒。', 'Shēngháo bìxū xīnxiān, fǒuzé róngyì yǐnqǐ shíwù zhòngdú.', 'Hàu phải thật tươi, nếu không rất dễ gây ngộ độc thực phẩm.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-8f330b618aef323cf24ab51f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-8e4115595ad3c2b9278b2e46.mp3', 66),
    ('芒果', 'mángguǒ', 'xoài', '这家店的芒果很甜，适合做甜点。', 'Zhè jiā diàn de mángguǒ hěn tián, shìhé zuò tiándiǎn.', 'Xoài ở quán này rất ngọt, thích hợp làm tráng miệng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-b8246e4fd8938af74519bafe.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-1441b54cec4534dad8d10aa9.mp3', 67),
    ('虾仁', 'xiārén', 'thịt tôm bóc nõn', '虾仁炒饭是本店招牌，如果没过敏可以尝试。', 'Xiārén chǎofàn shì běn diàn zhāopái, rúguǒ méi guòmǐn kěyǐ chángshì.', 'Cơm chiên tôm bóc nõn là món đặc trưng của quán, nếu không dị ứng có thể thử.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-5d8f75f8129ce0a00d2c8a41.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-318c8bd49c38cc9f8c8f6e01.mp3', 68),
    ('芹菜', 'qíncài', 'rau cần tây', '这道菜搭配芹菜，口感清爽。', 'Zhè dào cài dāpèi qíncài, kǒugǎn qīngshuǎng.', 'Món này kết hợp rau cần tây, ăn rất thanh mát.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-c1755c51d3a239460dc1575a.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-3009297b3e8f507e3cf8ff9c.mp3', 69),
    ('西红柿', 'xīhóngshì', 'cà chua', '西红柿炒蛋是很受欢迎的家常菜。', 'Xīhóngshì chǎo dàn shì hěn shòu huānyíng de jiācháng cài.', 'Cà chua xào trứng là món ăn gia đình rất được ưa thích.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-bb6da11cdcdf24add5ff4b56.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-abe0913215516ccfff338a87.mp3', 70),
    ('草莓', 'cǎoméi', 'dâu tây', '草莓含有丰富的维生素C，有助健康。', 'Cǎoméi hányǒu fēngfù de wéishēngsù C, yǒuzhù jiànkāng.', 'Dâu tây chứa nhiều vitamin C, giúp cải thiện sức khỏe.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-c76f6a79f6dbcf632fa5db9e.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-9bcc7eca640c7ea14a274894.mp3', 71),
    ('西兰花', 'xī lán huā', 'bông cải xanh', '西兰花炒得刚好，保持了脆嫩的口感。', 'Xī lán huā chǎo de gāng hǎo, bǎochí le cuì nèn de kǒugǎn.', 'Bông cải xanh xào vừa tới, giữ được độ giòn và ngon.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-1fdb83f31be268d5040782fb.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-93cdd8109b02507236d10685.mp3', 72),
    ('鲍鱼', 'bào yú', 'bào ngư', '鲍鱼是一种高档的海鲜，价格也比较贵。', 'Bào yú shì yì zhǒng gāodàng de hǎixiān, jiàgé yě bǐjiào guì.', 'Bào ngư là loại hải sản cao cấp, giá cũng khá đắt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-6adf70fb59011df302d7ea68.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-db20ba30a45e68a304f4164d.mp3', 73),
    ('油麦菜', 'yóumàicài', 'rau diếp thơm', '油麦菜清炒是我的最爱，简单又健康。', 'Yóu mài cài qīng chǎo shì wǒ de zuì ài, jiǎndān yòu jiànkāng.', 'Rau diếp thơm xào thanh là món tôi thích, vừa đơn giản vừa tốt cho sức khỏe.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-d3ba38c71d51821fca21b392.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-b723815df9b46f80c654e5fd.mp3', 74),
    ('柚子', 'yòu zi', 'bưởi', '柚子富含维生素C，是很好的水果选择。', 'Yòu zi fùhán wéishēngsù C, shì hěn hǎo de shuǐguǒ xuǎnzé.', 'Bưởi giàu vitamin C, là lựa chọn trái cây rất tốt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-9ef8346f7304ffdf5073021f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-d5fdcc9384e1baf4e1cf7442.mp3', 75),
    ('微辣', 'wēi là', 'ít cay', '我喜欢微辣的炒饭，味道刚刚好。', 'Wǒ xǐhuān wēi là de chǎofàn, wèidào gānggāng hǎo.', 'Tôi thích cơm rang ít cay, vị vừa phải.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-81813e0d8303da4d94232249.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-de7834316557f24fd96c63aa.mp3', 76),
    ('不辣', 'bù là', 'không cay', '我对辣椒过敏，请给我做不辣的菜。', 'Wǒ duì làjiāo guòmǐn, qǐng gěi wǒ zuò bù là de cài.', 'Tôi bị dị ứng ớt, làm cho tôi món không cay.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-8be2728d420ab2c9daa45ad0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-7e0353d77cbb9fafafd64f39.mp3', 77),
    ('甜', 'tián', 'ngọt', '这道甜点不太甜，非常适合夏天。', 'Zhè dào tiándiǎn bù tài tián, fēicháng shìhé xiàtiān.', 'Món tráng miệng này không quá ngọt, rất phù hợp mùa hè.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-10fe8c1b5c2274724ad3a7fd.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-1d4a1d7e22f9bf8049712e12.mp3', 78),
    ('咸', 'xián', 'mặn', '请帮我少放盐，这道菜太咸了。', 'Qǐng bāng wǒ shǎo fàng yán, zhè dào cài tài xián le.', 'Làm ơn cho ít muối, món này quá mặn rồi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-9f8c9685ea0178b68a646792.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-9ea59d330b530ab01616dd56.mp3', 79),
    ('淡', 'dàn', 'nhạt', '汤太淡了，可以加点盐吗？', 'Tāng tài dàn le, kěyǐ jiā diǎn yán ma?', 'Canh nhạt quá, có thể thêm chút muối không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-a12d77370b51064d664249fb.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-4cbc29b80979373799dcbb25.mp3', 80),
    ('苦', 'kǔ', 'đắng', '这杯茶有点苦，但很有养生效果。', 'Zhè bēi chá yǒudiǎn kǔ, dàn hěn yǒu yǎngshēng xiàoguǒ.', 'Ly trà này hơi đắng nhưng rất có tác dụng dưỡng sinh.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-0e63c34d213f6f6077d4325c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-129935fcca9a9cee324cc572.mp3', 81),
    ('香', 'xiāng', 'thơm', '这道菜炒得很香，让人食欲大开。', 'Zhè dào cài chǎo dé hěn xiāng, ràng rén shíyù dà kāi.', 'Món này xào rất thơm, khiến người ta rất thèm ăn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-cf4c4cd832e449cd305c9a9c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-0555a29fe7eb435a15177487.mp3', 82),
    ('浓郁', 'nóng yù', 'đậm vị', '这汤的味道浓郁，非常符合我的口味。', 'Zhè tāng de wèidào nóngyù, fēicháng fúhé wǒ de kǒuwèi.', 'Vị canh rất đậm đà, rất hợp khẩu vị tôi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-26404a2801baa04af461b144.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-bd17cbe78057126d08813063.mp3', 83),
    ('酱油', 'jiàngyóu', 'nước tương', '请少放酱油，我对盐分要控制。', 'Qǐng shǎo fàng jiàngyóu, wǒ duì yánfèn yào kòngzhì.', 'Xin cho ít nước tương, tôi phải kiểm soát lượng muối.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-afabf88f5c6141609048f03c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-ba7a30426e174925447d182e.mp3', 84),
    ('醋', 'cù', 'giấm', '这道凉拌菜用醋调味，非常开胃。', 'Zhè dào liángbàn cài yòng cù tiáowèi, fēicháng kāiwèi.', 'Món trộn lạnh này dùng giấm để nêm rất kích thích vị giác.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-56796b44de6a25a82fc873ca.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-0eb5f63a09bcf92999d17bc7.mp3', 85),
    ('胡椒粉', 'hújiāo fěn', 'tiêu bột', '请给我多加一点胡椒粉，我喜欢辣味。', 'Qǐng gěi wǒ duō jiā yīdiǎn hújiāo fěn, wǒ xǐhuān là wèi.', 'Làm ơn cho tôi thêm chút tiêu bột, tôi thích vị cay.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-d9bd29947df738b47de9e3a2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-6b1d78e04b173f6e5484bb0d.mp3', 86),
    ('辣椒', 'làjiāo', 'ớt', '我对辣椒不过敏，可以多放一点吗？', 'Wǒ duì làjiāo bù guòmǐn, kěyǐ duō fàng yīdiǎn ma?', 'Tôi không dị ứng ớt, có thể cho nhiều chút không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-fc12e809f63553544e91e760.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-95df6d058457125feee7dbd3.mp3', 87),
    ('少辣', 'shǎo là', 'ít cay', '我不能吃太辣，请给我少辣一点的菜。', 'Wǒ bù néng chī tài là, qǐng gěi wǒ shǎo là yīdiǎn de cài.', 'Tôi không ăn được cay nhiều, làm ơn cho tôi món ít cay.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-6d503bc49ea40a8bd969ec09.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-a350decc69205a152d17b13c.mp3', 88),
    ('甜味', 'tián wèi', 'vị ngọt', '这个甜味适中的饮料，非常适合饭后喝。', 'Zhège tiánwèi shìzhōng de yǐnliào, fēicháng shìhé fànhòu hē.', 'Nước uống vị ngọt vừa phải này rất thích hợp uống sau khi ăn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-f58a11ecb85ca285c4868225.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-541d45395a6a8b48f2823421.mp3', 89),
    ('酸味', 'suān wèi', 'vị chua', '沙拉里的酸味来自新鲜柠檬汁。', 'Shālā lǐ de suān wèi láizì xīnxiān níngméng zhī.', 'Vị chua trong salad là từ nước cốt chanh tươi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-87cc7fdaa8f6074cd8207e02.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-662cce5726374b2686433163.mp3', 90),
    ('咸味', 'xián wèi', 'vị mặn', '腌制的菜有明显的咸味，要注意盐分。', 'Yānzhì de cài yǒu míngxiǎn de xián wèi, yào zhùyì yánfèn.', 'Món muối có vị mặn rõ rệt, cần chú ý lượng muối.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-d2967ab4c1bbc7a9a97e5c0d.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-f498e5ec9c9e6522bc7e619b.mp3', 91),
    ('清淡', 'qīng dàn', 'vị thanh, nhạt', '我喜欢口味清淡的菜，吃起来舒服。', 'Wǒ xǐhuān kǒuwèi qīngdàn de cài, chī qǐlái shūfú.', 'Tôi thích món vị nhạt, ăn rất dễ chịu.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-acefcc8eba9c833e7ed00aee.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-c28f95e0cc81d02bd393a9a0.mp3', 92),
    ('苦味', 'kǔ wèi', 'vị đắng', '药膳里带有一点苦味，有助健康。', 'Yào shàn lǐ dàiyǒu yīdiǎn kǔ wèi, yǒu zhù jiànkāng.', 'Món thuốc ăn có chút vị đắng, tốt cho sức khỏe.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-ff0a9102ca05b684cf4bc5d2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-8dbca1e7ffbb64e14636da24.mp3', 93),
    ('香料', 'xiāngliào', 'gia vị thơm', '这道菜用了多种香料，味道特别。', 'Zhè dào cài yòng le duō zhǒng xiāngliào, wèidào tèbié.', 'Món này dùng nhiều gia vị thơm, vị rất đặc biệt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-387c5c4254aec1c56bd1a3b8.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-9a751e526de41881b095d9cd.mp3', 94),
    ('重口味', 'zhòng kǒuwèi', 'vị đậm, nồng nặc', '他喜欢重口味的食物，经常加辣加盐。', 'Tā xǐhuān zhòng kǒuwèi de shíwù, jīngcháng jiā là jiā yán.', 'Anh ấy thích món đậm đà, thường thêm ớt và muối.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-5f3a727494117c8fc71f9231.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-416fedc97f6e8e6fbeb94cb3.mp3', 95),
    ('黑胡椒', 'hēi hújiāo', 'tiêu đen', '牛排上撒了些黑胡椒，味道更鲜美。', 'Niúpái shàng sā le xiē hēi hújiāo, wèidào gèng xiānměi.', 'Trên bít tết rắc ít tiêu đen, vị ngon hơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-25c96b530ffb971a183054df.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-6cde2b07609766df26a3c7dc.mp3', 96),
    ('辣椒粉', 'làjiāo fěn', 'ớt bột', '这道菜放了辣椒粉，有明显的辣味。', 'Zhè dào cài fàng le làjiāo fěn, yǒu míngxiǎn de là wèi.', 'Món này có cho ớt bột, vị cay rõ rệt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-be396e27697b887878ecaa9c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-70b18cc1e5401eca6998881f.mp3', 97),
    ('香草', 'xiāngcǎo', 'thảo mộc thơm', '汤里加了香草，味道更加清新。', 'Tāng lǐ jiā le xiāngcǎo, wèidào gèng jiā qīngxīn.', 'Canh có thêm thảo mộc thơm, mùi vị tươi mát hơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-2086cb1986fb988265627c54.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-7408d26fc87cdb73a8280144.mp3', 98),
    ('芥末', 'jièmo', 'mù tạt', '请问芥末需要单独放吗？我怕口味重。', 'Qǐngwèn jièmó xūyào dāndú fàng ma? Wǒ pà kǒuwèi zhòng.', 'Xin hỏi có cần cho mù tạt riêng không? Tôi sợ mùi quá nồng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-45a4bc35a0a114eea380392b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-4f96e3fd72cdc116e1bf5384.mp3', 99),
    ('孜然', 'zīrán', 'hạt thì là', '烤肉用了孜然粉，味道很特别。', 'Kǎoròu yòng le zīrán fěn, wèidào hěn tèbié.', 'Thịt nướng dùng bột hạt thì là, vị rất đặc biệt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-e778fe9b247b31dd04bbd3d4.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-f7015c032c4ca2b1f81ff3e2.mp3', 100),
    ('煎', 'jiān', 'chiên (rán bằng ít dầu)', '厨师把鱼片煎至金黄，外皮酥脆。', 'Chú shī bǎ yú piàn jiān zhì jīn huáng, wài pí sū cuì.', 'Đầu bếp chiên cá đến khi vàng giòn bên ngoài.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-19f180e4410ecedf20b91a76.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-107a6fbae854403ca6c57b32.mp3', 101),
    ('炸', 'zhá', 'rán ngập dầu', '炸鸡块油炸得酥脆，是孩子们的最爱。', 'Zhá jī kuài yóu zhá dé sū cuì, shì hái zi men de zuì ài.', 'Gà rán ngập dầu giòn rụm, là món khoái khẩu của trẻ em.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-34c5155a43fbfd7a978a112f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-b870499955242be662107fa2.mp3', 102),
    ('煮', 'zhǔ', 'luộc, nấu', '这道汤需要煮两个小时才能入味。', 'Zhè dào tāng xū yào zhǔ liǎng gè xiǎo shí cái néng rù wèi.', 'Món canh này cần nấu hai tiếng mới thấm vị.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-b606bf981ff8f416dc07833b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-04d028125a804f7dfdb218a9.mp3', 103),
    ('蒸', 'zhēng', 'hấp', '鱼用蒸的方法，保持了鲜嫩的口感。', 'Yú yòng zhēng de fāng fǎ, bǎo chí le xiān nèn de kǒu gǎn.', 'Cá hấp giữ được độ tươi ngon và mềm mại.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-5b8dca68e725d658c1cc98b9.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-c40a5c59d6b69fc4dce1d3f9.mp3', 104),
    ('烤', 'kǎo', 'nướng', '烤鸭外皮酥脆，里面肉质鲜嫩。', 'Kǎo yā wài pí sū cuì, lǐ miàn ròu zhì xiān nèn.', 'Vịt nướng da giòn, thịt bên trong mềm ngọt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-f5a8e63b6f63b48ee9b0f86b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-9e68d71c71a3ecdbe84230de.mp3', 105),
    ('炖', 'dùn', 'hầm', '这道汤是用牛骨慢火炖制的，营养丰富。', 'Zhè dào tāng shì yòng niú gǔ màn huǒ dùn zhì de, yíng yǎng fēng fù.', 'Món canh được hầm xương bò lửa nhỏ, rất bổ dưỡng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-34b6d3f72de36b7e554bc804.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-6785c632aa25798cfcf23b65.mp3', 106),
    ('红烧', 'hóng shāo', 'kho (kho màu)', '红烧肉色泽红亮，味道咸甜适中。', 'Hóng shāo ròu sè zé hóng liàng, wèi dào xián tián shì zhōng.', 'Thịt kho màu đỏ bóng, vị mặn ngọt vừa phải.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-1cab25399a80166ae76b018a.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-ef77a2ad081462e76e22ca9e.mp3', 107),
    ('拌', 'bàn', 'trộn (gỏi, salad)', '凉拌黄瓜清爽开胃，很适合夏天吃。', 'Liáng bàn huáng guā qīng shuǎng kāi wèi, hěn shì hé xià tiān chī.', 'Dưa leo trộn lạnh mát mẻ, rất thích hợp mùa hè.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-9756f408bb0aedff8a3934c2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-a8faeec063bf0f490f3a0f57.mp3', 108),
    ('切片', 'qiē piàn', 'cắt lát', '师傅将肉切片得很薄，适合火锅涮煮。', 'Shī fù jiāng ròu qiē piàn dé hěn bó, shì hé huǒ guō shuàn zhǔ.', 'Đầu bếp cắt thịt lát mỏng, phù hợp nhúng lẩu.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-e1b4f02f91a8087ff77a1d40.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-f8a66644b2bf021160c00178.mp3', 109),
    ('剥皮', 'bō pí', 'bóc vỏ', '请帮我剥皮这个橙子，我怕弄脏手。', 'Qǐng bāng wǒ bō pí zhè gè chéng zi, wǒ pà nòng zāng shǒu.', 'Làm ơn bóc vỏ quả cam này giúp tôi, tôi sợ bẩn tay.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-6eeda9a2015a38f2b842a325.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-27f66ce1da08df95c0f6196a.mp3', 110),
    ('全熟', 'quán shú', 'chín kỹ', '我喜欢牛排全熟，确保肉质安全无风险。', 'Wǒ xǐ huān niú pái quán shú, què bǎo ròu zhì ān quán wú fēng xiǎn.', 'Tôi thích bít tết chín kỹ để đảm bảo an toàn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-c8fd39a346b34595e2ef1e74.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-467b9ea5e17db6cd9524c2f8.mp3', 111),
    ('五成熟', 'wǔ chéngshú', 'chín vừa', '请帮我把牛肉做成五成熟，保持嫩度。', 'Qǐng bāng wǒ bǎ niú ròu zuò chéng wǔ chéng shú, bǎo chí nèn dù.', 'Vui lòng làm thịt bò chín vừa để vẫn giữ được độ mềm.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-79201ad7f1f7956ddff5d63d.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-90445d4bdc4ffdc8e0aa20e5.mp3', 112),
    ('热的', 'rè de', 'nóng (thức ăn)', '这碗汤请给我热的，我不喜欢冷的。', 'Zhè wǎn tāng qǐng gěi wǒ rè de, wǒ bù xǐ huān lěng de.', 'Tô canh này cho tôi ăn nóng, tôi không thích lạnh.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-5180e38d15f9a80accafb587.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-ccc4bf2b80359b480d49d2c9.mp3', 113),
    ('凉的', 'liáng de', 'lạnh (thức ăn)', '夏天我喜欢吃凉的炒面，有清凉感。', 'Xià tiān wǒ xǐ huān chī liáng de chǎo miàn, yǒu qīng liáng gǎn.', 'Mùa hè tôi thích ăn mì xào lạnh cho mát.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-a84afe86377f40511895dee8.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-8f64d06644f99988ef661c0a.mp3', 114),
    ('切丁', 'qiē dīng', 'cắt hạt lựu', '菜里需要切丁的胡萝卜增加口感。', 'Cài lǐ xū yào qiē dīng de hú luó bo zēng jiā kǒu gǎn.', 'Món ăn cần cà rốt cắt hạt lựu để tăng độ ngon.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-2cb8f60fe1f70a1eca54254b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-6b0adaaa8483835ddaa88488.mp3', 115),
    ('腌制', 'yān zhì', 'ướp, muối chua', '这道菜的肉先腌制，味道更加入味。', 'Zhè dào cài de ròu xiān yān zhì, wèi dào gèng jiā rù wèi.', 'Món thịt này được ướp trước nên rất đậm đà.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-82d4e528f8168e8d9a3e748d.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-7100d782cb5c9917d5adcbdd.mp3', 116),
    ('焯水', 'chāoshuǐ', 'chần sơ', '蔬菜焯水后，颜色会更绿，看起来新鲜。', 'Shū cài chuō shuǐ hòu, yán sè huì gèng lǜ, kàn qǐ lái xīn xiān.', 'Sau khi chần sơ, rau sẽ xanh hơn và trông tươi hơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-15de0800bc7ea351fe1c160c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-f4b0ab53ddb1a10e1cf7754c.mp3', 117),
    ('捞出', 'lāo chū', 'vớt ra (khi nấu)', '面条煮熟后要捞出，避免过熟变软。', 'Miàn tiáo zhǔ shú hòu yào lāo chū, bì miǎn guò shú biàn ruǎn.', 'Mì chín cần vớt ra ngay để không bị nát.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-c59197ce1311548864173d25.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-05931299c6fa428337546c81.mp3', 118),
    ('剁碎', 'duò suì', 'băm nhỏ', '请将大蒜剁碎后加入菜里提味。', 'Qǐng jiāng dà suàn duò suì hòu jiā rù cài lǐ tí wèi.', 'Hãy băm nhỏ tỏi rồi cho vào món ăn để tăng mùi vị.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-9d2a59cbf5cdf1ad8b2ffb90.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-fa0dee59e210d88800c6410b.mp3', 119),
    ('焖', 'mèn', 'om, hầm kín', '红烧鱼要先煎后焖，味道更鲜美。', 'Hóng shāo yú yào xiān jiān hòu mèn, wèi dào gèng xiān měi.', 'Cá kho cần được chiên trước rồi om thì hương vị mới ngon hơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-7ad8271e9fc0aea75ebb66b0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-9ef8ecb190a8a42a7cb1bf5c.mp3', 120),
    ('滑炒', 'huá chǎo', 'xào nhanh, đều tay', '青菜用滑炒的手法保持鲜嫩脆口。', 'Qīng cài yòng huá chǎo de shǒu fǎ bǎo chí xiān nèn cuì kǒu.', 'Rau xanh xào nhanh giữ được độ tươi ngon.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-191cb820566a2d6e2e3af4c8.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-dd17c219f10e7af8a7989d2c.mp3', 121),
    ('急火', 'jí huǒ', 'lửa lớn', '炒菜时用急火可以保持材料的鲜美。', 'Chǎo cài shí yòng jí huǒ kě yǐ bǎo chí cái liào de xiān měi.', 'Xào bằng lửa lớn giữ nguyên vị tươi ngon của nguyên liệu.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-cde30808a204bb6d35d7baf0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-701f9ec98bda73be6445781f.mp3', 122),
    ('慢火', 'màn huǒ', 'lửa nhỏ', '炖汤要用慢火，保证食材充分释放味道。', 'Dùn tāng yào yòng màn huǒ, bǎo zhèng shí cái chōng fèn shì fàng wèi dào.', 'Hầm canh phải dùng lửa nhỏ để nguyên liệu thấm đều.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-be62648aee92412f488bd40a.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-0d882836572937672abc2f41.mp3', 123),
    ('翻炒', 'fān chǎo', 'xào đảo đều', '炒饭过程中要不断翻炒，避免粘锅。', 'Chǎo fàn guò chéng zhōng yào bù duàn fān chǎo, bì miǎn zhān guō.', 'Khi chiên cơm phải liên tục đảo đều mới không dính nồi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-2eacf19c373a9672438dceb7.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-606119706327912fb1c76146.mp3', 124),
    ('炒', 'chǎo', 'xào', '厨师用大火炒青菜，保持清脆口感。', 'Chúshī yòng dàhuǒ chǎo qīngcài, bǎochí qīngcuì kǒugǎn.', 'Đầu bếp xào rau trên lửa lớn để giữ độ giòn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-470282cc335411b768c5e96b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-a0b80fe4e0228cff545ff2ec.mp3', 125),
    ('炒饭', 'chǎofàn', 'cơm chiên', '我想点一份炒饭，不要放鸡蛋，谢谢。', 'Wǒ xiǎng diǎn yí fèn chǎofàn, bú yào fàng jīdàn, xièxie.', 'Tôi muốn gọi một phần cơm chiên, không bỏ trứng, cảm ơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-a3fb9bc3abb90f1f96a2c0c8.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-8b0dd02df335c79e86fde4a2.mp3', 126),
    ('粥', 'zhōu', 'cháo', '我早餐常常喝一碗粥，暖胃又健康。', 'Wǒ zǎocān chángcháng hē yì wǎn zhōu, nuǎn wèi yòu jiànkāng.', 'Tôi thường uống một bát cháo vào bữa sáng, vừa ấm bụng vừa khỏe mạnh.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-8f89b12a0cc0e4bfba854717.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-601e5fab4cb4eb7392e4b5d2.mp3', 127),
    ('热汤', 'rè tāng', 'súp nóng', '请给我来一碗热汤，里面不要加奶制品，我对乳糖不耐受。', 'Qǐng gěi wǒ lái yì wǎn rè tāng, lǐmiàn bú yào jiā nǎizhìpǐn, wǒ duì rǔtáng bù nàishòu.', 'Làm ơn cho tôi một bát súp nóng, đừng cho sản phẩm từ sữa vì tôi bị không dung nạp lactose.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-f53829305e7f1227b717b834.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-2c7ddffc58078b165e6ab37a.mp3', 128),
    ('包子', 'bāozi', 'bánh bao', '请问这个包子里有鸡蛋吗？我对鸡蛋过敏。', 'Qǐngwèn zhège bāozi lǐ yǒu jīdàn ma? Wǒ duì jīdàn guòmǐn.', 'Cho hỏi bánh bao này có trứng không? Tôi bị dị ứng trứng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-787d89bb2ba8a2c6d2e2a937.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-135615040e11ad9f5310432c.mp3', 129),
    ('甜点', 'tiándiǎn', 'món tráng miệng', '我们想尝试几款甜点，你们有什么推荐的吗？', 'Wǒmen xiǎng chángshì jǐ kuǎn tiándiǎn, nǐmen yǒu shénme tuījiàn de ma?', 'Chúng tôi muốn thử vài loại món tráng miệng, các bạn có gợi ý gì không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-5c85ed36608492b075f8c4f0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-483ee081bf5c1cce079fbf8c.mp3', 130),
    ('奶茶', 'nǎichá', 'trà sữa', '我喜欢加珍珠的奶茶，但是对乳糖过敏要注意。', 'Wǒ xǐhuān jiā zhēnzhū de nǎichá, dànshì duì rǔtáng guòmǐn yào zhùyì.', 'Tôi thích trà sữa có trân châu, nhưng phải chú ý vì tôi bị dị ứng lactose.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-54b77038f0df26556488e019.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-c1da127fa9946bc9d1d8461b.mp3', 131),
    ('咖啡', 'kāfēi', 'cà phê', '请给我一杯不加糖的黑咖啡，谢谢！', 'Qǐng gěi wǒ yì bēi bú jiā táng de hēi kāfēi, xièxie!', 'Làm ơn cho tôi một ly cà phê đen không đường, cảm ơn!', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-720ec669f15b87b1ac631c4b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-ea6a85836ad7acbc5ed08725.mp3', 132),
    ('炒面', 'chǎomiàn', 'mì xào', '这份炒面味道不错，但我对海鲜过敏，别放虾。', 'Zhè fèn chǎomiàn wèidào bùcuò, dàn wǒ duì hǎixiān guòmǐn, bié fàng xiā.', 'Mì xào này vị khá ngon, nhưng tôi dị ứng hải sản, đừng bỏ tôm vào.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-7e598e83a1b6cfae2a8755b2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-1d2b59420731fde71e7ab6d5.mp3', 133),
    ('汤面', 'tāngmiàn', 'mì nước', '我要一碗汤面，不含鸡蛋，谢谢。', 'Wǒ yào yì wǎn tāngmiàn, bù hán jīdàn, xièxie.', 'Tôi muốn một bát mì nước, không có trứng, cảm ơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-b91ff716555c2529a1370e48.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-95248120ba4e0d9da0b19b96.mp3', 134),
    ('米饭', 'mǐfàn', 'cơm', '请给我一碗米饭，配这道红烧肉。', 'Qǐng gěi wǒ yì wǎn mǐfàn, pèi zhè dào hóngshāoròu.', 'Cho tôi một bát cơm để ăn cùng món thịt kho này.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-e233a13a49e5110647b50596.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-ed38930b0c5df1fdaa940c9c.mp3', 135),
    ('蔬菜沙拉', 'shūcài shālā', 'salad rau củ', '请给我一份蔬菜沙拉，不要加坚果，我对坚果过敏。', 'Qǐng gěi wǒ yí fèn shūcài shālā, bú yào jiā jiānguǒ, wǒ duì jiānguǒ guòmǐn.', 'Cho tôi một phần salad rau củ, đừng bỏ hạt, tôi bị dị ứng hạt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-03b927d9ae2322be2b0ec5ff.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-e2bc048df891969462608fb7.mp3', 136),
    ('饺子', 'jiǎozi', 'sủi cảo', '这家店的猪肉白菜饺子很受欢迎。', 'Zhè jiā diàn de zhūròu báicài jiǎozi hěn shòu huānyíng.', 'Sủi cảo nhân thịt heo và cải thảo của quán này rất được yêu thích.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-f00ffdf5cd1b6828afc251b6.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-5ff89ffb0a10acaf30c7d7b1.mp3', 137),
    ('冰淇淋', 'bīngqílín', 'món kem lạnh', '孩子想在饭后吃一份香草冰淇淋。', 'Háizi xiǎng zài fànhòu chī yí fèn xiāngcǎo bīngqílín.', 'Đứa trẻ muốn ăn một phần kem vani sau bữa cơm.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-7ea01af14f9347464110646b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-8944e8803651e3743a4e945d.mp3', 138),
    ('红茶', 'hóngchá', 'trà đen', '我喜欢喝红茶，但请不要加牛奶，我对乳糖过敏。', 'Wǒ xǐhuān hē hóngchá, dàn qǐng bú yào jiā niúnǎi, wǒ duì rǔtáng guòmǐn.', 'Tôi thích uống trà đen, nhưng đừng cho sữa, tôi bị dị ứng lactose.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-252a9a8f569801e870ae3abc.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-425242ffa2ef73998b0cb356.mp3', 139),
    ('冰咖啡', 'bīng kāfēi', 'cà phê đá', '请给我一杯冰咖啡，不加糖，非常感谢。', 'Qǐng gěi wǒ yì bēi bīng kāfēi, bú jiā táng, fēicháng gǎnxiè.', 'Làm ơn cho tôi một ly cà phê đá không đường, rất cảm ơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-b0f4ce7ad590d514c29b70da.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-743747bd839bf6aa203bdcc5.mp3', 140),
    ('鲜榨果汁', 'xiān zhà guǒzhī', 'nước ép tươi', '有鲜榨果汁菜单吗？我想喝无添加糖的。', 'Yǒu xiān zhà guǒzhī càidān ma? Wǒ xiǎng hē wú tiānjiā táng de.', 'Có thực đơn nước ép tươi không? Tôi muốn uống loại không thêm đường.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-de74dccba2d3171bef0831e1.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-4e03161f80ef2aa07c1e83b5.mp3', 141),
    ('生啤酒', 'shēng píjiǔ', 'bia tươi', '请给我一杯生啤酒，冰镇至最佳温度。', 'Qǐng gěi wǒ yì bēi shēng píjiǔ, bīng zhèn zhì zuì jiā wēndù.', 'Cho tôi một ly bia tươi, làm lạnh đến nhiệt độ tốt nhất.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-03326fd32054d1800c45cc3c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-5d2101da3557720d9dc96cb7.mp3', 142),
    ('炒乌冬面', 'chǎo wūdōng miàn', 'mì udon xào', '我想点花生过敏的替代品，不要加花生的炒乌冬面。', 'Wǒ xiǎng diǎn huāshēng guòmǐn de tìdài pǐn, bú yào jiā huāshēng de chǎo wūdōng miàn.', 'Tôi muốn gọi món thay thế cho dị ứng đậu phộng, đừng bỏ đậu phộng trong mì udon xào.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-2f2c5490c7933441d0353721.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-cb3bcdc3d0c61fe3eb54ca2b.mp3', 143),
    ('海鲜汤', 'hǎixiān tāng', 'canh hải sản', '请注意，我海鲜过敏，别给我这道海鲜汤。', 'Qǐng zhùyì, wǒ hǎixiān guòmǐn, bié gěi wǒ zhè dào hǎixiān tāng.', 'Xin lưu ý, tôi bị dị ứng hải sản, đừng cho tôi món canh hải sản này.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-6ba70921e3c848ffb3e3c726.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-47610117acdda6cae8eb15e7.mp3', 144),
    ('水果茶', 'shuǐguǒ chá', 'trà hoa quả', '我不喝加糖的水果茶，可以帮我准备无糖版本吗？', 'Wǒ bù hē jiā táng de shuǐguǒ chá, kěyǐ bāng wǒ zhǔnbèi wú táng bǎnběn ma?', 'Tôi không uống trà hoa quả có đường, bạn có thể chuẩn bị loại không đường giúp tôi không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-9235ae9956b1cc59905a9146.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-88fdebe7c57b2f8ec01a17ad.mp3', 145),
    ('鸡汤面', 'jītāng miàn', 'mì nước gà', '我对鸡蛋和牛奶过敏，点一碗鸡汤面时请不要放蛋。', 'Wǒ duì jīdàn hé niúnǎi guòmǐn, diǎn yì wǎn jītāng miàn shí qǐng bú yào fàng dàn.', 'Tôi dị ứng trứng và sữa, khi gọi mì nước gà xin đừng cho trứng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-906f309db27936cece30bf49.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-af1d13e2165988a49aaeec8b.mp3', 146),
    ('红豆沙包', 'hóngdòu shā bāo', 'bánh bao nhân đậu đỏ ngọt', '红豆沙包不要加糖粉，我喜欢口味清淡。', 'Hóngdòu shā bāo bú yào jiā táng fěn, wǒ xǐhuān kǒuwèi qīngdàn.', 'Bánh bao nhân đậu đỏ đừng rắc đường bột, tôi thích vị nhạt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-0f6bebbab2482acb35dc63b7.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-a521f8ecc913391b3ea5f8c1.mp3', 147),
    ('水果冻', 'shuǐguǒ dòng', 'thạch trái cây', '吃水果冻之前，请确认里面不含任何坚果成分。', 'Chī shuǐguǒ dòng zhīqián, qǐng quèrèn lǐmiàn bù hán rènhé jiānguǒ chéngfèn.', 'Trước khi ăn thạch trái cây, làm ơn xác nhận không có thành phần hạt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-7c6724efa1e945fb0f9bbf7f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-6f245ef2d5c49de4528070de.mp3', 148),
    ('水果沙拉', 'shuǐguǒ shālā', 'salad hoa quả', '这道水果沙拉新鲜健康，适合夏天清爽享用。', 'Zhè dào shuǐguǒ shālā xīnxiān jiànkāng, shìhé xiàtiān qīngshuǎng xiǎngyòng.', 'Món salad hoa quả này tươi ngon và khỏe mạnh, thích hợp thưởng thức vào mùa hè mát mẻ.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-eafe766c4873a11a9028c3a0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-8bc01c65cef18f001d28b525.mp3', 149),
    ('矿泉水', 'kuàngquánshuǐ', 'nước khoáng', '请给我一瓶常温矿泉水。', 'Qǐng gěi wǒ yì píng chángwēn kuàngquánshuǐ.', 'Vui lòng cho tôi một chai nước khoáng ở nhiệt độ thường.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-6b1311e9a899a0d494a7e3dc.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-56240bfa1c1da1950add8c42.mp3', 150),
    ('花生过敏', 'huāshēng guòmǐn', 'dị ứng đậu phộng', '对花生过敏的客人请避免点含花生的菜品。', 'Duì huāshēng guòmǐn de kèrén qǐng bìmiǎn diǎn hán huāshēng de càipǐn.', 'Khách bị dị ứng đậu phộng xin tránh gọi các món có đậu phộng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-80bafb5ee48e957bc4318d74.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-f29bf06811550bc92f221ae9.mp3', 151),
    ('海鲜过敏', 'hǎixiān guòmǐn', 'dị ứng hải sản', '顾客有海鲜过敏，请确认菜单无海鲜成分。', 'Gùkè yǒu hǎixiān guòmǐn, qǐng quèrèn càidān wú hǎixiān chéngfèn.', 'Khách bị dị ứng hải sản, xin xác nhận trong thực đơn không có thành phần hải sản.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-2ff30559f8c15797788be2aa.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-eb25683b57a5b85db16b7d79.mp3', 152),
    ('乳糖不耐受', 'rǔtáng bù nài shòu', 'không dung nạp lactose', '乳糖不耐受者应避免饮用含牛奶的饮料。', 'Rǔtáng bù nài shòu zhě yīng bìmiǎn yǐnyòng hán niúnǎi de yǐnliào.', 'Người không dung nạp lactose nên tránh uống đồ uống có sữa bò.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-e6a162c5f2551a90b21a414f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-4d2c1f900b28c7cc569663c8.mp3', 153),
    ('无麸质', 'wú fū zhì', 'không gluten', '这道菜是无麸质配方，适合麸质过敏者。', 'Zhè dào cài shì wú fū zhì pèifāng, shìhé fūzhì guòmǐn zhě.', 'Món này không chứa gluten, thích hợp cho người dị ứng gluten.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-d325bcc69680f24e425ca6b2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-fb3eb70277ea5627e8ad0e2e.mp3', 154),
    ('纯素食', 'chún sùshí', 'thuần chay', '他坚持纯素食，不吃任何动物制品。', 'Tā jiānchí chún sùshí, bù chī rènhé dòngwù zhìpǐn.', 'Anh ấy kiên trì ăn thuần chay, không ăn bất kỳ sản phẩm động vật nào.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-ec5630e825630b8fd65866ef.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-4bd4228d797add4176a65d16.mp3', 155),
    ('低糖', 'dī táng', 'ít đường', '请给我一杯低糖饮料，因为我控制糖分摄入。', 'Qǐng gěi wǒ yī bēi dī táng yǐnliào, yīnwèi wǒ kòngzhì tángfèn shèrù.', 'Xin cho tôi một ly đồ uống ít đường vì tôi kiểm soát lượng đường tiêu thụ.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-fa5fd544289275201aaec223.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-e015d44c018d46a33e3f2a69.mp3', 156),
    ('低盐', 'dī yán', 'ít muối', '这道菜请做成低盐口味，谢谢。', 'Zhè dào cài qǐng zuò chéng dī yán kǒuwèi, xièxiè.', 'Món này xin làm nhạt, ít muối, cảm ơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-4c1999bd0122b6935a3c8cc3.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-8f9f0a2ea9c99361b2230919.mp3', 157),
    ('少油', 'shǎo yóu', 'ít dầu', '我想吃少油的食物，对健康比较好。', 'Wǒ xiǎng chī shǎo yóu de shíwù, duì jiànkāng bǐjiào hǎo.', 'Tôi muốn ăn món ít dầu, tốt cho sức khỏe hơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-16b0cdf665d97df9e3ef2ff9.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-a15e9b88c32c0ef422232d48.mp3', 158),
    ('不加葱', 'bù jiā cōng', 'không hành lá', '这道菜请不加葱，我对葱过敏。', 'Zhè dào cài qǐng bù jiā cōng, wǒ duì cōng guòmǐn.', 'Món này xin đừng thêm hành lá, tôi bị dị ứng với hành.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-ae4ee6f127b8549f392b887e.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-e5911dce943dc0c3f25e4ca2.mp3', 159),
    ('不加香菜', 'bù jiā xiāngcài', 'không rau mùi', '我不喜欢香菜，能不能不加香菜？', 'Wǒ bù xǐhuān xiāngcài, néng bùnéng bù jiā xiāngcài?', 'Tôi không thích rau mùi, có thể không cho rau mùi được không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-7124aba0e08bc82713a1a1d0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-df9d2982f8a74cef8c8ee328.mp3', 160),
    ('成分', 'chéngfèn', 'thành phần', '请告诉我这道菜的所有成分。', 'Qǐng gàosù wǒ zhè dào cài de suǒyǒu chéngfèn.', 'Xin cho tôi biết tất cả thành phần của món này.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-3989a72d75bfa601348a6fd9.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-5ef39c802409bc0c126a382b.mp3', 161),
    ('致敏物质', 'zhìmǐn wùzhì', 'chất gây dị ứng', '请确认这道菜是否含有常见的致敏物质。', 'Qǐng quèrèn zhè dào cài shìfǒu hányǒu chángjiàn de zhìmǐn wùzhì.', 'Xin xác nhận món này có chứa các chất gây dị ứng phổ biến không.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-77b6c8147b846dde305ea142.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-e4a4011ca748a1504819348d.mp3', 162),
    ('避免食用', 'bìmiǎn shíyòng', 'tránh sử dụng (thực phẩm)', '对海鲜过敏者应避免食用相关菜品。', 'Duì hǎixiān guòmǐn zhě yīng bìmiǎn shíyòng xiāngguān càipǐn.', 'Người dị ứng hải sản nên tránh dùng các món liên quan.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-4114332c1463f1fbd0e411fa.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-693c77604964ad3762dea71a.mp3', 163),
    ('无添加糖', 'wú tiānjiā táng', 'không thêm đường', '请制作无添加糖的甜点，谢谢。', 'Qǐng zhìzuò wú tiānjiā táng de tiándiǎn, xièxiè.', 'Xin làm món tráng miệng không thêm đường, cảm ơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-0d3b1f9e414d6aeac62e0f35.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-b8a2d2284381c201a34490ac.mp3', 164),
    ('无添加盐', 'wú tiānjiā yán', 'không thêm muối', '这道菜请无添加盐，保持原味。', 'Zhè dào cài qǐng wú tiānjiā yán, bǎochí yuánwèi.', 'Món này xin không thêm muối, giữ hương vị tự nhiên.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-47bc8cb8493ce71e34293a7e.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-afcfcc2b358c1e66d8ee5b8d.mp3', 165),
    ('不含乳制品', 'bù hán rǔ zhìpǐn', 'không chứa sản phẩm từ sữa', '请问这道菜是否不含乳制品？', 'Qǐngwèn zhè dào cài shìfǒu bù hán rǔ zhìpǐn?', 'Xin hỏi món này có không chứa sản phẩm từ sữa không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-3c95c97679b04a0f4ea06361.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-0159ef8b8e2fce94f3c41e54.mp3', 166),
    ('过敏史', 'guòmǐn shǐ', 'tiền sử dị ứng', '您有任何过敏史需要告诉我们吗？', 'Nín yǒu rènhé guòmǐn shǐ xūyào gàosù wǒmen ma?', 'Quý khách có tiền sử dị ứng gì cần báo cho chúng tôi không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-757eea5728af4e2d4bff03eb.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-ab83c06426690e5bef46cf60.mp3', 167),
    ('避免交叉污染', 'bìmiǎn jiāochā wūrǎn', 'tránh nhiễm chéo (dị ứng)', '厨房严格避免交叉污染，保证食品安全。', 'Chúfáng yángé bìmiǎn jiāochā wūrǎn, bǎozhèng shípǐn ānquán.', 'Bếp nghiêm túc tránh nhiễm chéo bảo đảm an toàn thực phẩm.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-cc75623e6587948743a3bb24.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-6b38c9e1c0dcd135a656d7ec.mp3', 168),
    ('限制摄入', 'xiànzhì shèrù', 'hạn chế hấp thụ', '医生建议限制摄入高盐食物。', 'Yīshēng jiànyì xiànzhì shèrù gāo yán shíwù.', 'Bác sĩ khuyên hạn chế hấp thụ thực phẩm nhiều muối.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-e5bf13232add7a32dca66aff.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-c09324288a8f7b08f8a5cd2f.mp3', 169),
    ('无动物成分', 'wú dòngwù chéngfèn', 'không có thành phần động vật', '这款饮料是无动物成分，适合素食者。', 'Zhè kuǎn yǐnliào shì wú dòngwù chéngfèn, shìhé sùshí zhě.', 'Đồ uống này không có thành phần động vật, phù hợp người ăn chay.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-0e8e7a40e2fa1847a86cf0f1.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-e7d24ae4a54abce281382103.mp3', 170),
    ('食物过敏', 'shíwù guòmǐn', 'dị ứng thực phẩm', '食物过敏可能引起严重反应，请谨慎选择。', 'Shíwù guòmǐn kěnéng yǐnqǐ yánzhòng fǎnyìng, qǐng jǐnshèn xuǎnzé.', 'Dị ứng thực phẩm có thể gây phản ứng nghiêm trọng, xin chọn lựa cẩn thận.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-b88fe0a5474f19239d5b39ff.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-1726dcfc5b1914757f17c009.mp3', 171),
    ('不含鸡蛋', 'bù hán jīdàn', 'không chứa trứng', '孩子对鸡蛋过敏，请做一份不含鸡蛋的餐。', 'Háizi duì jīdàn guòmǐn, qǐng zuò yí fèn bù hán jīdàn de cān.', 'Đứa trẻ dị ứng với trứng, vui lòng làm một phần ăn không chứa trứng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-822983f1fd0b5c8acad852b8.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-3b340b47cd20699b6ee0d81c.mp3', 172),
    ('低脂', 'dī zhī', 'ít chất béo', '我需要低脂饮食，请推荐相关菜品。', 'Wǒ xūyào dī zhī yǐnshí, qǐng tuījiàn xiāngguān càipǐn.', 'Tôi cần chế độ ăn ít chất béo, xin giới thiệu món phù hợp.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-7fec18f88f2751a19d1ad4b9.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-0e6efeaa469526760bb79dc5.mp3', 173),
    ('坚果过敏', 'jiānguǒ guòmǐn', 'dị ứng với các loại hạt', '我有坚果过敏，请确认甜点里没有坚果。', 'Wǒ yǒu jiānguǒ guòmǐn, qǐng quèrèn tiándiǎn lǐ méiyǒu jiānguǒ.', 'Tôi dị ứng với các loại hạt, vui lòng xác nhận món tráng miệng không có hạt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-0bf6d040f0175b46699a2fc9.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-32a31288af109e5fbf201336.mp3', 174),
    ('无糖', 'wú táng', 'không đường', '我要一杯无糖的绿茶，谢谢。', 'Wǒ yào yī bēi wú táng de lǜchá, xièxiè.', 'Tôi muốn một ly trà xanh không đường, cảm ơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-33e934d5eab50d6a7208383c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-6293415bdc8f4102cd146094.mp3', 175),
    ('筷子', 'kuàizi', 'đũa', '请给我一双干净的筷子，谢谢。', 'Qǐng gěi wǒ yī shuāng gānjìng de kuàizi, xièxiè.', 'Làm ơn cho tôi một đôi đũa sạch, cảm ơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-399893f69b9b91c914e0ac4d.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-2b83ca4c1a373fbaed11b215.mp3', 176),
    ('勺子', 'sháozi', 'thìa', '这道汤可以用勺子来喝，更方便。', 'Zhè dào tāng kěyǐ yòng sháozi lái hē, gèng fāngbiàn.', 'Món canh này có thể dùng thìa để uống, tiện hơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-72407ec665b596b8ef23a080.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-b3cba89bb2e68e3044d3e4da.mp3', 177),
    ('碗', 'wǎn', 'bát', '请帮我换一个干净的碗，我刚才不小心弄脏了。', 'Qǐng bāng wǒ huàn yī gè gānjìng de wǎn, wǒ gāngcái bù xiǎoxīn nòng zāng le.', 'Làm ơn giúp tôi đổi một chiếc bát sạch, tôi vừa mới vô tình làm bẩn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-41bb76350c7ec2d811b56440.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-4f10c15651978522117519d9.mp3', 178),
    ('盘子', 'pánzi', 'đĩa', '麻烦把菜放在干净的盘子里，谢谢。', 'Máfan bǎ cài fàng zài gānjìng de pánzi lǐ, xièxiè.', 'Phiền để món ăn vào đĩa sạch, cảm ơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-f13de7aaabf883748d6d1b68.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-dc1e72e1ea69e31fd3abd176.mp3', 179),
