    ('吸管', 'xīguǎn', 'ống hút', '这杯果汁不用塑料吸管。', 'Zhè bēi guǒzhī bú yòng sùliào xīguǎn.', 'Ly nước ép này không cần ống hút nhựa.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-6f11ed20eb709140d3d41e37.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-c25ccc4d4fa718ce756e7b07.mp3', 191),
    ('外卖订单', 'wàimài dìngdān', 'đơn hàng giao đồ ăn', '请确认一下我的外卖订单有没有问题。', 'Qǐng quèrèn yīxià wǒ de wàimài dìngdān yǒu méiyǒu wèntí.', 'Xin xác nhận đơn hàng giao đồ ăn của tôi có vấn đề không.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-731555e69f9fd3116767d5a1.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-8307268d3cbbf43da35e2382.mp3', 192),
    ('找零', 'zhǎolíng', 'tiền thối lại', '我给你一百块，请找零给我。', 'Wǒ gěi nǐ yī bǎi kuài, qǐng zhǎolíng gěi wǒ.', 'Tôi đưa bạn một trăm đồng, xin trả lại tiền thối cho tôi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-8cadb3b3e326bbd53a88c85d.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-a943703df1e96c560020ddd9.mp3', 193),
    ('收据', 'shōujù', 'biên lai', '结账以后请把收据给我。', 'Jiézhàng yǐhòu qǐng bǎ shōujù gěi wǒ.', 'Sau khi thanh toán, vui lòng đưa biên lai cho tôi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-f1bd7f7711b02233aad936c4.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-cb644dd6ba876cf0f98aa9a6.mp3', 194),
    ('支付方式', 'zhīfù fāngshì', 'phương thức thanh toán', '请问你们接受哪些支付方式？', 'Qǐngwèn nǐmen jiēshòu nǎxiē zhīfù fāngshì?', 'Xin hỏi quán chấp nhận những hình thức thanh toán nào?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-ca7223717fa6f6810a2105cb.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-e4c1c3d0145c173da1ea677e.mp3', 195),
    ('纸袋', 'zhǐdài', 'túi giấy đựng đồ mang về', '请给我一个纸袋装外卖，谢谢。', 'Qǐng gěi wǒ yī gè zhǐdài zhuāng wàimài, xièxiè.', 'Làm ơn cho tôi một túi giấy đựng đồ mang về, cảm ơn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-b595af4c6c8011bf7905c634.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-ecb65541c2967bd15c13d556.mp3', 196),
    ('环保袋', 'huánbǎo dài', 'túi môi trường, túi thân thiện với môi trường', '我自己带了环保袋，可以帮我装外卖吗？', 'Wǒ zìjǐ dài le huánbǎo dài, kěyǐ bāng wǒ zhuāng wàimài ma?', 'Tôi mang túi môi trường của riêng mình, bạn có thể giúp tôi đóng gói đồ mang về không?', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-113f452a10f2012fe6ae0c84.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-d4f539613533d2d896d74451.mp3', 197),
    ('确认订单', 'quèrèn dìngdān', 'xác nhận đơn hàng', '请先确认订单内容是否正确，再付款。', 'Qǐng xiān quèrèn dìngdān nèiróng shìfǒu zhèngquè, zài fùkuǎn.', 'Xin vui lòng xác nhận nội dung đơn hàng đúng hay không trước khi thanh toán.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-f6c1322ffbdc91daa5a8199d.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-bf432d40b0e31b5ba567bdac.mp3', 198),
    ('服务态度', 'fúwù tàidù', 'thái độ phục vụ', '服务态度很好，让人用餐很愉快。', 'Fúwù tàidù hěn hǎo, ràng rén yòngcān hěn yúkuài.', 'Thái độ phục vụ rất tốt, khiến khách dùng bữa rất vui vẻ.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-5199cad72e41008c258f5bbe.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-9904ee569338990e21c04e66.mp3', 199),
    ('打包盒', 'dǎbāo hé', 'hộp đựng mang về', '请给我一个打包盒，我要带剩菜回家。', 'Qǐng gěi wǒ yī gè dǎbāo hé, wǒ yào dài shèng cài huí jiā.', 'Làm ơn cho tôi một hộp đựng mang về, tôi muốn mang phần thừa về nhà.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/word-4635fde00d1f242d86af7bf7.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/am-thuc-goi-mon-200/sentence-5144aaf247b7f69cd1204c52.mp3', 200)
) as card(
  chinese, pinyin, meaning_vi, example_cn, example_pinyin,
  example_vi, word_audio_url, sentence_audio_url, position
)
on conflict (template_deck_id, chinese) do update
set
  pinyin = excluded.pinyin,
  meaning_vi = excluded.meaning_vi,
  example_cn = excluded.example_cn,
  example_pinyin = excluded.example_pinyin,
  example_vi = excluded.example_vi,
  word_audio_url = excluded.word_audio_url,
  sentence_audio_url = excluded.sentence_audio_url,
  position = excluded.position;

delete from public.template_cards
where template_deck_id = (
  select id from public.template_decks where slug = 'am-thuc-goi-mon-200'
)
